" 2>&1

kubectl exec -n mongodb mongo-maintenance -- mongosh --quiet --eval "
// Read current rs config from local.system.replset
use local
var config = db.system.replset.findOne();
printjson(config);
" 2>&1

kubectl exec -n mongodb mongo-maintenance -- mongosh --quiet --eval "
var config = db.getSiblingDB('local').system.replset.findOne();
printjson(config);
" 2>&1

kubectl exec -n mongodb mongo-maintenance -- mongosh --quiet --eval "
var local = db.getSiblingDB('local');
var config = local.system.replset.findOne();

// Keep only first 3 members and increment version
config.members = config.members.slice(0, 3);
config.version = config.version + 1;

local.system.replset.replaceOne({_id: config._id}, config);
print('Replica set config updated to 3 members, version: ' + config.version);

// Verify
var updated = local.system.replset.findOne();
print('Updated member count: ' + updated.members.length);
updated.members.forEach(function(m) { print(' - ' + m.host); });
" 2>&1
